# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, jsonify, session
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret_key'
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///database.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password = db.Column(db.String(120), nullable=False)
    is_two_factor_enabled = db.Column(db.Boolean, default=False)

@app.route('/api/profile', methods=['POST'])
def update_profile():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    is_two_factor_enabled = data.get('isTwoFactorEnabled')

    user = User.query.filter_by(id=session['user_id']).first()

    if email:
        user.email = email
    if password:
        user.password = password
    if is_two_factor_enabled is not None:
        user.is_two_factor_enabled = is_two_factor_enabled

    db.session.commit()

    return jsonify({'message': 'Profile updated successfully'}), 200